27	error_t dkg_ac(job_mp_t& job, ecurve_t curve, buf_t& sid, const crypto::ss::ac_t ac,
28	               const party_set_t& quorum_party_set, key_t& key) {
29	  return eckey::key_share_mp_t::dkg_ac(job, curve, sid, ac, quorum_party_set, key);
30	}
31	
32	error_t refresh_ac(job_mp_t& job, ecurve_t curve, buf_t& sid, const crypto::ss::ac_t ac,
33	                   const party_set_t& quorum_party_set, key_t& key, key_t& new_key) {
34	  return eckey::key_share_mp_t::refresh_ac(job, curve, sid, ac, quorum_party_set, key, new_key);
