583	error_t key_share_mp_t::reconstruct_pub_additive_shares(const crypto::ss::node_t* node,
584	                                                        const std::set<crypto::pname_t>& quorum_names,
585	                                                        const crypto::pname_t target, ecc_point_t& pub_additive_shares,
586	                                                        bool& is_satisfied) const {
587	  error_t rv = UNINITIALIZED_ERROR;
588	  int n = node->get_n();
589	
590	  switch (node->type) {
591	    case node_e::LEAF: {
592	      pub_additive_shares = curve.infinity();
593	      if (node->name == target) {
594	        pub_additive_shares = Qis.at(node->name);
595	      }
596	      is_satisfied = quorum_names.find(node->name) != quorum_names.end();
597	    } break;
598	
599	    case node_e::OR:
600	      pub_additive_shares = curve.infinity();
601	      is_satisfied = false;
602	      for (int i = 0; i < n; i++) {
603	        ecc_point_t additive_share_from_child = curve.infinity();
604	        bool child_is_satisfied = false;
605	        rv = reconstruct_pub_additive_shares(node->children[i], quorum_names, target, additive_share_from_child,
606	                                             child_is_satisfied);
607	        is_satisfied = is_satisfied || child_is_satisfied;
608	        if (rv == E_INSUFFICIENT) {
609	          rv = SUCCESS;
610	          continue;
611	        }
612	        if (rv) return rv;
613	        if (!child_is_satisfied) {
614	          continue;
615	        }
616	        pub_additive_shares = additive_share_from_child;
617	        break;
618	      }
619	      break;
620	    case node_e::AND:
621	      pub_additive_shares = curve.infinity();
622	      is_satisfied = true;
623	      for (int i = 0; i < n; i++) {
624	        ecc_point_t additive_share_from_child = curve.infinity();
625	        bool child_is_satisfied = false;
626	        rv = reconstruct_pub_additive_shares(node->children[i], quorum_names, target, additive_share_from_child,
627	                                             child_is_satisfied);
628	        is_satisfied = is_satisfied && child_is_satisfied;
629	        if (rv) {
630	          return rv;
631	        }
632	
633	        if (!additive_share_from_child.is_infinity()) {
634	          pub_additive_shares = additive_share_from_child;
635	        }
636	      }
637	      break;
638	
639	    case node_e::THRESHOLD: {
640	      std::vector<bn_t> interp_pids;
641	      interp_pids.reserve(node->threshold);
642	      ecc_point_t share = curve.infinity();
643	      bn_t share_pid = 0;
644	      int satisfied_count = 0;
645	
646	      for (int i = 0; i < n; i++) {
647	        ecc_point_t share_from_child = curve.infinity();
648	        bool child_is_satisfied = false;
649	        rv = reconstruct_pub_additive_shares(node->children[i], quorum_names, target, share_from_child,
650	                                             child_is_satisfied);
651	        if (rv == E_INSUFFICIENT) {
652	          continue;
653	        }
654	        if (rv) return rv;
655	
656	        if (!child_is_satisfied) continue;
657	
658	        satisfied_count++;
659	        const bn_t child_pid = node->children[i]->get_pid();
660	        const bool child_is_selected = int(interp_pids.size()) < node->threshold;
661	        if (!child_is_selected) continue;
662	
663	        interp_pids.push_back(child_pid);
664	        if (!share_from_child.is_infinity()) {
665	          share_pid = child_pid;
666	          share = share_from_child;
667	        }
668	      }
669	
670	      if (satisfied_count < node->threshold) {
671	        dylog_disable_scope_t dylog_disable_scope;
672	        return coinbase::error(E_INSUFFICIENT);
673	      }
674	      is_satisfied = true;
675	
676	      // Target party is outside the selected quorum subtree for this threshold node.
677	      if (share_pid == 0) {
678	        pub_additive_shares = curve.infinity();
679	        break;
680	      }
681	
682	      cb_assert(int(interp_pids.size()) == node->threshold);
683	
684	      pub_additive_shares = crypto::lagrange_partial_interpolate_exponent(0, {share}, {share_pid}, interp_pids);
685	    } break;
686	    case node_e::NONE: {
687	      return coinbase::error(E_CRYPTO, "key_share_mp_t::reconstruct_pub_additive_shares: none node");
688	    } break;
689	  }
690	
691	  return SUCCESS;
692	}
693	
694	error_t key_share_mp_t::to_additive_share(const crypto::ss::ac_t ac, const std::set<crypto::pname_t>& quorum_names,
695	                                          key_share_mp_t& additive_share) {
696	  if (!ac.enough_for_quorum(quorum_names)) {
697	    return coinbase::error(E_INSUFFICIENT);
698	  }
699	  error_t rv = UNINITIALIZED_ERROR;
700	  const mod_t& q = curve.order();
701	  bn_t new_x_share;
702	  bool _ignore_is_satisfied = false;
703	  if (rv = reconstruct_additive_share(q, ac.root, quorum_names, new_x_share, _ignore_is_satisfied)) return rv;
704	
705	  party_map_t<ecc_point_t> new_Qis;
706	  std::vector<crypto::pname_t> quorum_names_vec(quorum_names.begin(), quorum_names.end());
707	
708	  for (size_t j = 0; j < quorum_names_vec.size(); j++) {
709	    crypto::vartime_scope_t vartime_scope;
710	    bool _ignore_is_satisfied = false;
711	    ecc_point_t new_Qi;
712	    if (rv = reconstruct_pub_additive_shares(ac.root, quorum_names, quorum_names_vec[j], new_Qi, _ignore_is_satisfied))
713	      return rv;
714	    new_Qis[quorum_names_vec[j]] = new_Qi;
715	  }
716	
717	  additive_share.x_share = new_x_share;
718	  additive_share.Q = Q;
719	  additive_share.Qis = new_Qis;
720	  additive_share.curve = curve;
721	  additive_share.party_name = party_name;
722	
723	  return SUCCESS;
724	}
