17	class party_set_t {
18	 public:
19	  party_set_t(uint64_t p = 0) : peers(p) {}
20	  bool has(int party_index) const { return (peers & mask_of_party(party_index)) != 0; }
21	  static party_set_t of(int party_index) { return party_set_t(mask_of_party(party_index)); }
22	  bool is_empty() const { return peers == 0; }
23	  void add(int party_index) { peers |= mask_of_party(party_index); }
24	  void remove(int party_index) { peers &= ~mask_of_party(party_index); }
25	  static party_set_t all() { return party_set_t(0xffffffffffffffff); }
26	  static party_set_t empty() { return party_set_t(0); }
27	  uint64_t peers;
28	
29	 private:
30	  static uint64_t mask_of_party(int party_index) { return uint64_t(1) << party_index; }
31	};
