33	class job_mp_t {
34	  /* Helper functions for serializing/deserializing messages for multi parties */
35	
36	  template <typename... MSGS>
37	  std::vector<buf_t> pack_msgs(party_set_t set, MSGS&... msgs) {
38	    std::vector<buf_t> out(n_parties);
39	    for (int i = 0; i < n_parties; i++) {
40	      if (!set.has(i)) continue;
41	      out[i] = pack_msgs_for_party(i, msgs...);
42	    }
43	    return out;
44	  }
45	
46	  template <typename... MSGS>
47	  error_t unpack_msgs(party_set_t set, const std::vector<buf_t>& received, MSGS&... msgs) {
48	    error_t rv = UNINITIALIZED_ERROR;
49	    for (int i = 0; i < n_parties; i++) {
50	      if (!set.has(i) || i == party_index) continue;
51	      if (rv = unpack_msgs_for_party(i, received[i], msgs...)) return rv;
52	    }
53	    return SUCCESS;
54	  }
55	
56	  template <typename... MSGS>
57	  static buf_t pack_msgs_for_party(int index, MSGS&... msgs) {
58	    int n;
59	    {
60	      coinbase::converter_t converter(true);
61	      pack_msgs_converter_helper(converter, index, msgs...);
62	      n = converter.get_offset();
63	    }
64	
65	    buf_t out(n);
66	
67	    {
68	      coinbase::converter_t converter(out.data());
69	      pack_msgs_converter_helper(converter, index, msgs...);
70	    }
71	    return out;
72	  }
73	
74	  template <typename... MSGS>
75	  static error_t unpack_msgs_for_party(int party_index, mem_t mem, MSGS&... msgs) {
76	    error_t rv = UNINITIALIZED_ERROR;
77	    coinbase::converter_t converter(mem);
78	    (
79	        [&](auto& arg) {
80	          if (!converter.is_error()) arg.unpack(converter, party_index);
81	        }(msgs),
82	        ...);
83	    if (rv = converter.get_rv()) return rv;
84	    if (converter.get_offset() != converter.get_size()) return coinbase::error(E_FORMAT);
85	    return SUCCESS;
86	  }
87	
88	  template <typename... MSGS>
89	  static void pack_msgs_converter_helper(coinbase::converter_t& converter, int index, MSGS&... msgs) {
90	    ([&](auto& msg) { msg.pack(converter, index); }(msgs), ...);
91	  }
92	
93	  /* Helper functions for group messaging between for multiple groups */
94	
95	  template <typename MSG>
96	  std::vector<buf_t> pack_multi_sets_msgs(std::tuple<party_set_t&, party_set_t&, MSG&> msg_ctx) {
97	    std::vector<buf_t> out(n_parties);
98	    for (int i = 0; i < n_parties; i++) {
99	      if (!std::get<0>(msg_ctx).has(i)) continue;
100	      out[i] = pack_msgs_for_party(i, std::get<2>(msg_ctx));
101	    }
102	    return out;
103	  }
104	
105	  // Helper for `combine_packed_msgs` to apply the pack function at a specific index across all vectors
106	  template <typename Tuple, std::size_t... Is>
107	  buf_t apply_bundle_at_index(const Tuple& tuple, std::size_t index, std::index_sequence<Is...>) {
108	    return coinbase::ser(std::get<Is>(tuple)[index]...);
109	  }
110	
111	  // Combine a tuple of packed_msgs (vector<buf_t>) into a single packed_msgs
112	  template <typename... BUFS>
113	  std::vector<buf_t> combine_packed_msgs(const std::tuple<BUFS...>& tuple) {
114	    std::vector<buf_t> result(n_parties);
115	
116	    for (std::size_t i = 0; i < n_parties; ++i) {
117	      result[i] = apply_bundle_at_index(tuple, i, std::index_sequence_for<BUFS...>{});
118	    }
119	
120	    return result;
121	  }
122	
123	  // Helper for `split_packed_msgs` to apply the unpack function at a specific index across all vectors
124	  template <typename Tuple, std::size_t... Is>
125	  error_t apply_unbundle_at_index(mem_t out, Tuple& tuple, std::size_t index, std::index_sequence<Is...>) {
126	    return coinbase::deser(out, std::get<Is>(tuple)[index]...);
127	  }
128	
129	  // Reverse of `combine_packed_msgs`
130	  template <typename... Ts>
131	  error_t split_packed_msgs(const std::vector<buf_t>& bufs, std::tuple<Ts...>& tuple) {
132	    error_t rv = UNINITIALIZED_ERROR;
133	
134	    for (std::size_t i = 0; i < n_parties; ++i) {
135	      mem_t mem = bufs[i];
136	      if (rv = apply_unbundle_at_index(mem, tuple, i, std::index_sequence_for<Ts...>{})) return rv;
137	    }
138	
139	    return SUCCESS;
140	  }
141	
142	  template <typename MSG>
143	  error_t unpack_msg_ctx(const std::vector<buf_t>& bufs, std::tuple<party_set_t&, party_set_t&, MSG&> msg_ctx) {
144	    return unpack_msgs(std::get<1>(msg_ctx), bufs, std::get<2>(msg_ctx));
145	  }
146	  template <typename Tuple1, typename Tuple2, std::size_t... Is>
147	  void unpack_multi_sets_msgs_helper(Tuple1& t1, Tuple2& t2, std::index_sequence<Is...>) {
148	    // Use the index sequence to access elements from both tuples
149	    (unpack_msg_ctx(std::get<Is>(t1), std::get<Is>(t2)), ...);
150	  }
151	  template <typename... Ts1, typename... Ts2>
152	  void unpack_multi_sets_tupled_msgs(std::tuple<Ts1...>& t1, std::tuple<Ts2&...> t2) {
153	    static_assert(sizeof...(Ts1) == sizeof...(Ts2), "Tuples must have the same length to unpack");
154	    unpack_multi_sets_msgs_helper(t1, t2, std::index_sequence_for<Ts1...>{});
155	  }
156	
157	  /* functions to send and received serialized multi-party messages */
158	
159	  error_t send_to_parties(party_set_t set, const std::vector<buf_t>& in);
160	  error_t receive_from_parties(party_set_t set, std::vector<buf_t>& v);
161	
162	 protected:
163	  bool message_sending = false;
164	  party_idx_t party_index;
165	  int n_parties;
166	  std::vector<crypto::mpc_pid_t> pids;
167	  std::vector<crypto::pname_t> names;
168	  // Transport lifetime:
169	  // - If the job is constructed with a `shared_ptr`, it keeps the transport alive.
170	  // - If the job is constructed with a `data_transport_i&`, it stores a non-owning
171	  //   pointer; the caller must ensure the transport outlives protocol execution.
172	  std::shared_ptr<coinbase::api::data_transport_i> transport_ptr;
173	  coinbase::api::data_transport_i* transport_raw = nullptr;
174	
175	 public:
176	  job_mp_t(int index, std::vector<crypto::pname_t> pnames,
177	           std::shared_ptr<coinbase::api::data_transport_i> tptr = nullptr)
178	      : party_index(index),
179	        n_parties(pnames.size()),
180	        transport_ptr(std::move(tptr)),
181	        transport_raw(transport_ptr.get()) {
182	    if (party_index < 0 || party_index >= n_parties) coinbase::error(E_BADARG, "invalid party_index");
183	    this->names = pnames;
184	    for (const auto& name : pnames) {
185	      pids.push_back(crypto::pid_from_name(name));
186	    }
187	    cb_assert(pids.size() >= 2 && "at least 2 parties are required");
188	    cb_assert(pids.size() <= 64 && "at most 64 parties are supported");
189	  }
190	
191	  job_mp_t(int index, std::vector<crypto::pname_t> pnames, coinbase::api::data_transport_i& transport)
192	      : job_mp_t(index, std::move(pnames), /*tptr=*/nullptr) {
193	    transport_raw = &transport;
194	  }
195	
196	  virtual error_t send_impl(party_idx_t to, mem_t msg) {
197	    if (!transport_raw) return E_NET_GENERAL;
198	    return transport_raw->send(to, msg);
199	  }
200	  virtual error_t receive_impl(party_idx_t from, buf_t& msg) {
201	    if (!transport_raw) return E_NET_GENERAL;
202	    return transport_raw->receive(from, msg);
203	  }
204	  virtual error_t receive_many_impl(std::vector<party_idx_t> from_set, std::vector<buf_t>& outs);
205	
206	  void set_transport(party_idx_t idx, std::shared_ptr<coinbase::api::data_transport_i> ptr) {
207	    party_index = idx;
208	    transport_ptr = std::move(ptr);
209	    transport_raw = transport_ptr.get();
210	  }
211	
212	  void set_transport(party_idx_t idx, coinbase::api::data_transport_i& transport) {
213	    party_index = idx;
214	    transport_ptr.reset();
215	    transport_raw = &transport;
216	  }
