218	  /* MPC Properties */
219	
220	  int get_n_parties() const { return n_parties; }
221	  party_idx_t get_party_idx() const { return party_index; }
222	  virtual bool is_party_idx(party_idx_t i) const { return i == party_index; }
223	
224	  const crypto::mpc_pid_t& get_pid() const { return pids[get_party_idx()]; }
225	  const crypto::mpc_pid_t& get_pid(party_idx_t index) const { return pids[index]; }
226	  const std::vector<crypto::mpc_pid_t>& get_pids() const { return pids; }
227	
228	  const crypto::pname_t& get_name() const { return names[get_party_idx()]; }
229	  const crypto::pname_t& get_name(party_idx_t index) const { return names[index]; }
230	  const std::vector<crypto::pname_t>& get_names() const { return names; }
