232	  /* MPC messaging */
233	
234	  error_t mpc_abort(error_t rv, const std::string& message = "") { return coinbase::error(rv); }
235	
236	  template <typename... MSGS>
237	  error_t send(party_idx_t to, MSGS&... msgs) {
238	    return send_impl(to, ser(msgs...));
239	  }
240	
241	  template <typename... MSGS>
242	  error_t receive(party_idx_t from, MSGS&... msgs) {
243	    error_t rv = UNINITIALIZED_ERROR;
244	
245	    buf_t buf;
246	    if (rv = receive_impl(from, buf)) return rv;
247	    if (buf.size() <= 0) return coinbase::error(E_NET_GENERAL);  // deserialization length validation
248	
249	    if (rv = deser(buf, msgs...)) return rv;
250	
251	    return SUCCESS;
252	  }
253	
254	  template <typename... MSGS>
255	  error_t send_receive_message(party_idx_t from, party_idx_t to, MSGS&... msgs) {
256	    error_t rv = UNINITIALIZED_ERROR;
257	
258	    message_sending = true;
259	
260	    if (is_party_idx(from)) {
261	      if (rv = send(to, msgs...)) return rv;
262	    }
263	    if (is_party_idx(to)) {
264	      if (rv = receive(from, msgs...)) return rv;
265	    }
266	
267	    message_sending = false;
268	
269	    return SUCCESS;
270	  }
271	
272	  template <typename... MSGS>
273	  error_t group_message(party_set_t to_set, party_set_t from_set, MSGS&... msgs) {
274	    error_t rv = UNINITIALIZED_ERROR;
275	
276	    if (!to_set.is_empty()) {
277	      std::vector<buf_t> send = pack_msgs(to_set, msgs...);
278	      if (rv = send_to_parties(to_set, send)) return rv;
279	    }
280	    if (!from_set.is_empty()) {
281	      std::vector<buf_t> receive;
282	      if (rv = receive_from_parties(from_set, receive)) return rv;
283	      if (rv = unpack_msgs(from_set, receive, msgs...)) return rv;
284	    }
285	
286	    return SUCCESS;
287	  }
288	
289	  // Group messaging for messages that involve different group of sender and receivers. It will bundle the messages for
290	  // each pairs of parties, which is different from calling the group_message for a fixed set of sender and receiver
291	  // multiple times.
292	  template <typename... MSG_TUPLES>
293	  error_t group_message(const MSG_TUPLES&... msg_tuples) {
294	    error_t rv = UNINITIALIZED_ERROR;
295	    auto packed_msgs_tuple = std::make_tuple(pack_multi_sets_msgs(msg_tuples)...);
296	    std::vector<buf_t> packed_msgs = combine_packed_msgs(packed_msgs_tuple);
297	
298	    if (rv = send_to_parties(party_set_t::all(), packed_msgs)) return rv;
299	    if (rv = receive_from_parties(party_set_t::all(), packed_msgs)) return rv;
300	
301	    if (rv = split_packed_msgs(packed_msgs, packed_msgs_tuple)) return rv;
302	    unpack_multi_sets_tupled_msgs(packed_msgs_tuple, std::tie(msg_tuples...));
303	
304	    return SUCCESS;
305	  }
306	
307	  template <typename... MSGS>
308	  error_t plain_broadcast(MSGS&... msgs) {
309	    return group_message(party_set_t::all(), party_set_t::all(), msgs...);
310	  }
311	
312	  template <typename... MSGS>
313	  error_t send_message_all_to_one(party_idx_t to, MSGS&... msgs) {
314	    error_t rv = UNINITIALIZED_ERROR;
315	
316	    if (party_index == to) {
317	      if (rv = group_message(party_set_t::empty(), party_set_t::all(), msgs...)) return rv;
318	    } else {
319	      if (rv = group_message(party_set_t::of(to), party_set_t::empty(), msgs...)) return rv;
320	    }
321	    return SUCCESS;
322	  }
