326	  // uniform message is for sending identical contents to other parties
327	  template <typename T>
328	  class uniform_msg_t : public T {
329	    friend class job_mp_t;
330	    void pack(coinbase::converter_t& c, int index) { c.convert(msg); }
331	    void unpack(coinbase::converter_t& c, int index) {
332	      if (index == job->get_party_idx())
333	        c.convert(msg);
334	      else
335	        c.convert(inbox[index]);
336	    }
337	
338	    job_mp_t* job;
339	    std::vector<T> inbox;
340	
341	   public:
342	    uniform_msg_t(job_mp_t* job, const T& src) : T(src), job(job), inbox(job->get_n_parties()) {
343	      inbox[job->get_party_idx()] = msg;
344	    }
345	
346	    uniform_msg_t(const uniform_msg_t& other) : T((const T&)other), job(other.job), inbox(other.inbox) {}
347	    uniform_msg_t& operator=(const uniform_msg_t& other) {
348	      if (this != &other) {
349	        (T&)(*this) = (const T&)other;
350	        job = other.job;
351	        inbox = other.inbox;
352	      }
353	      return *this;
354	    }
355	    uniform_msg_t(uniform_msg_t&& other) noexcept
356	        : T(std::move((T&)other)), job(other.job), inbox(std::move(other.inbox)) {}
357	    uniform_msg_t& operator=(uniform_msg_t&& other) noexcept {
358	      if (this != &other) {
359	        (T&)(*this) = std::move((T&)other);
360	        job = other.job;
361	        inbox = std::move(other.inbox);
362	      }
363	      return *this;
364	    }
365	    ~uniform_msg_t() = default;
366	
367	    void convert(coinbase::converter_t& c) { c.convert(msg); }
368	
369	    T& msg = *this;
370	    T& received(int index) {
371	      int n = job->get_n_parties();
372	      cb_assert(index >= 0 && index < n && "uniform_msg_t::received index out of range");
373	      return (index == job->get_party_idx()) ? msg : inbox[index];
374	    }
375	    std::vector<T>& all_received() {
376	      inbox[job->get_party_idx()] = msg;
377	      return inbox;
378	    }
379	  };
