381	  // nonuniform message is for sending different contents to each other parties
382	  // Note that there are inplace and non-inplace variables for different use cases. See the constructor comments.
383	  template <typename T>
384	  class nonuniform_msg_t {
385	    friend class job_mp_t;
386	    void pack(coinbase::converter_t& c, int index) { c.convert(msgs[index]); }
387	    void unpack(coinbase::converter_t& c, int index) {
388	      if (is_inplace)
389	        c.convert(msgs[index]);
390	      else
391	        c.convert((index == job->get_party_idx()) ? msgs[index] : inbox[index]);
392	    }
393	
394	    job_mp_t* job;
395	    std::vector<T> inbox;
396	    bool is_inplace = false;
397	
398	   public:
399	    nonuniform_msg_t(job_mp_t* job)
400	        : job(job), msgs(job->get_n_parties()), inbox(job->get_n_parties()), is_inplace(false) {}
401	    // For inplace messages where sending and receiving use same slots.
402	    // It is suitable when in a round, each party is either sender or receiver but not both at the same time.
403	    nonuniform_msg_t(job_mp_t* job, std::function<T(int i)>& f) : job(job), is_inplace(true) {
404	      int n = job->get_n_parties();
405	      msgs.reserve(n);
406	      for (int i = 0; i < n; i++) msgs.push_back(f(i));
407	    }
408	
409	    T& operator[](int index) { return msgs[index]; };
410	    const T& operator[](int index) const { return msgs[index]; };
411	    T& received(int index) {
412	      int n = job->get_n_parties();
413	      cb_assert(index >= 0 && index < n && "nonuniform_msg_t::received index out of range");
414	      return is_inplace ? msgs[index] : ((index == job->get_party_idx()) ? msgs[index] : inbox[index]);
415	    }
416	
417	    void convert(coinbase::converter_t& c) { c.convert(msgs); }
418	
419	    std::vector<T> msgs;
420	  };
421	
422	  // To bundle MPC messages. Useful when we can only pass a single parameter between functions.
423	  template <typename T>
424	  class msg_tuple_t {
425	   public:
426	    msg_tuple_t(T&& src) : msg(src) {}
427	    void pack(coinbase::converter_t& c, int index) {
428	      for_tuple(msg, [&](auto& arg) { arg.pack(c, index); });
429	    }
430	    void unpack(coinbase::converter_t& c, int index) {
431	      for_tuple(msg, [&](auto& arg) {
432	        if (!c.is_error()) arg.unpack(c, index);
433	      });
434	    }
435	
436	   private:
437	    T msg;
438	  };
