440	  // Functions to create message containers
441	  template <typename T>
442	  uniform_msg_t<T> uniform_msg() {
443	    return uniform_msg_t<T>(this, T());
444	  }
445	  template <typename T>
446	  uniform_msg_t<T> uniform_msg(const T& src) {
447	    return uniform_msg_t<T>(this, src);
448	  }
449	  template <typename T>
450	  nonuniform_msg_t<T> nonuniform_msg() {
451	    return nonuniform_msg_t<T>(this);
452	  }
453	  template <typename T>
454	  nonuniform_msg_t<T> inplace_msg(std::function<T(int i)>&& f) {
455	    return nonuniform_msg_t<T>(this, f);
456	  }
457	  template <typename... ARGS>
458	  static auto tie_msgs(ARGS&... args) {
459	    return msg_tuple_t(std::tie(args...));
460	  }
