8	void uc_dl_t::prove(const ecc_point_t& Q, const bn_t& w, mem_t session_id, uint64_t aux) {
9	  std::vector<bn_t> r(params.rho);
10	  ecurve_t curve = Q.get_curve();
11	  const auto& G = curve.generator();
12	  const mod_t& q = curve.order();
13	  int rho = params.rho;
14	
15	  cb_assert(w < q && "w exceeds the order of the curve");
16	
17	  A.resize(rho);
18	  e.resize(rho);
19	  z.resize(rho);
20	
21	  bn_t z_tag;
22	  bn_t q_value = bn_t(q);
23	  buf_t common_hash;
24	
25	  fischlin_prove(
26	      params,
27	      // initialize
28	      [&]() {
29	        for (int i = 0; i < rho; i++) {
30	          r[i] = bn_t::rand(q);
31	          A[i] = r[i] * G;
32	        }
33	        common_hash = crypto::ro::hash_string(G, Q, A, session_id, aux).bitlen(2 * SEC_P_COM);
34	      },
35	
36	      // response_begin
37	      [&](int i) { z_tag = r[i]; },
38	
39	      // hash
40	      [&](int i, int e_tag) -> uint32_t { return hash32bit_for_zk_fischlin(common_hash, i, e_tag, z_tag); },
41	
42	      // save
43	      [&](int i, int e_tag) {
44	        e[i] = e_tag;
45	        z[i] = z_tag;
46	      },
47	
48	      // response_next
49	      [&](int e_tag) {
50	        int res = bn_mod_add_fixed_top(z_tag, z_tag, w, q_value);
51	        cb_assert(res && "z' = z' + w (mod q) failed");
52	      });
53	}
